const url = 'http://127.0.0.1:3000/api/pin?type=SOME_STRING_VALUE&id=SOME_STRING_VALUE';
const options = {method: 'DELETE', headers: {Authorization: 'Bearer REPLACE_BEARER_TOKEN'}};

try {
  const response = await fetch(url, options);
  const data = await response.json();
  console.log(data);
} catch (error) {
  console.error(error);
}

const http = require('http');

const options = {
  method: 'DELETE',
  hostname: '127.0.0.1',
  port: '3000',
  path: '/api/pin?type=SOME_STRING_VALUE&id=SOME_STRING_VALUE',
  headers: {
    Authorization: 'Bearer REPLACE_BEARER_TOKEN'
  }
};

const req = http.request(options, function (res) {
  const chunks = [];

  res.on('data', function (chunk) {
    chunks.push(chunk);
  });

  res.on('end', function () {
    const body = Buffer.concat(chunks);
    console.log(body.toString());
  });
});

req.end();

